import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAudits, Audit, AuditIssue } from '@/hooks/useAudits';
import { usePolicies } from '@/hooks/usePolicies';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Search,
    Filter,
    Loader2,
    CheckCircle,
    AlertTriangle,
    XCircle,
    Clock,
    Play,
    Eye,
    Sparkles,
    FileSearch,
    TrendingUp,
    ChevronLeft,
    ChevronRight,
    RefreshCw,
    ShieldCheck,
    Zap,
    Briefcase,
    Activity,
    Award,
    CheckCircle as CheckCircle2
} from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { motion, AnimatePresence } from 'framer-motion';

const PAGE_SIZE = 20;

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Auditorias() {
    const navigate = useNavigate();
    const { audits, isLoading, runBatchAudit } = useAudits();
    const { policies } = usePolicies();
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [page, setPage] = useState(0);
    const [selectedAudit, setSelectedAudit] = useState<Audit | null>(null);
    const [selectedPolicyId, setSelectedPolicyId] = useState<string>('default');

    const filteredAudits = audits.filter(a => {
        const matchesSearch = !search ||
            a.creatives?.name?.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'all' || a.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    const paginatedAudits = filteredAudits.slice(
        page * PAGE_SIZE,
        (page + 1) * PAGE_SIZE
    );
    const totalPages = Math.ceil(filteredAudits.length / PAGE_SIZE);

    const stats = {
        total: audits.length,
        approved: audits.filter(a => a.status === 'approved').length,
        pending: audits.filter(a => a.status === 'pending').length,
        rejected: audits.filter(a => a.status === 'rejected').length,
        avgCompliance: audits.length > 0
            ? audits.reduce((acc, a) => acc + (a.compliance_score || 0), 0) / audits.length
            : 0,
    };

    const getStatusBadge = (status: string | null) => {
        const config: Record<string, { color: string; icon: React.ElementType; label: string }> = {
            approved: { color: 'emerald-500', icon: CheckCircle, label: 'Conforme' },
            pending: { color: 'amber-500', icon: Clock, label: 'Processando' },
            rejected: { color: 'rose-500', icon: XCircle, label: 'Risco Detectado' },
        };
        const cfg = config[status || 'pending'] || config.pending;
        const Icon = cfg.icon;
        return (
            <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full flex items-center gap-2 bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20`}>
                <Icon className="w-3.5 h-3.5" />
                {cfg.label}
            </span>
        );
    };

    const getScoreColor = (score: number | null) => {
        if (!score) return 'text-ch-text-muted';
        if (score >= 80) return 'text-emerald-500';
        if (score >= 60) return 'text-amber-500';
        return 'text-rose-500';
    };

    const getIssueSeverityIcon = (severity: string) => {
        switch (severity) {
            case 'error':
                return <XCircle className="w-4 h-4 text-rose-500" />;
            case 'warning':
                return <AlertTriangle className="w-4 h-4 text-amber-500" />;
            default:
                return <CheckCircle className="w-4 h-4 text-blue-500" />;
        }
    };

    const handleRunBatchAudit = async () => {
        await runBatchAudit.mutateAsync({
            policyId: selectedPolicyId === 'default' ? undefined : selectedPolicyId,
            limit: 50,
        });
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <ShieldCheck className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wide">Scanner de Conformidade</span>
                    </div>
                    <h1 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Auditorias de Performance</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Análise automatizada de conformidade para escala global.</p>
                </div>

                <div className="flex flex-wrap items-center gap-3">
                    <Select value={selectedPolicyId} onValueChange={setSelectedPolicyId}>
                        <SelectTrigger className="w-56 bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl text-[10px] font-black uppercase tracking-widest">
                            <SelectValue placeholder="Protocolo de Política" />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10">
                            <SelectItem value="default" className="text-[10px] font-bold uppercase tracking-widest">Protocolo Padrão CH</SelectItem>
                            {policies.map(p => (
                                <SelectItem key={p.id} value={p.id} className="text-[10px] font-bold uppercase tracking-widest">{p.name}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    <Button
                        onClick={handleRunBatchAudit}
                        disabled={runBatchAudit.isPending}
                        className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-12 px-8 shadow-xl group"
                    >
                        {runBatchAudit.isPending ? (
                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        ) : (
                            <Zap className="w-4 h-4 mr-2 group-hover:animate-pulse" />
                        )}
                        Iniciar Varredura
                    </Button>
                </div>
            </motion.div>

            {/* Stats Overview */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                {[
                    { label: 'Relatórios', value: stats.total, icon: FileSearch, color: 'ch-orange' },
                    { label: 'Conformes', value: stats.approved, icon: CheckCircle, color: 'emerald-500' },
                    { label: 'Em Fila', value: stats.pending, icon: Clock, color: 'amber-500' },
                    { label: 'Riscos', value: stats.rejected, icon: AlertTriangle, color: 'rose-500' },
                    {
                        label: 'Índice Global',
                        value: `${stats.avgCompliance.toFixed(0)}%`,
                        icon: Award,
                        color: 'purple-500',
                        customColor: getScoreColor(stats.avgCompliance)
                    },
                ].map((stat) => (
                    <motion.div key={stat.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-3xl p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-3 mb-4">
                            <div className={`p-2 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-4 h-4 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">{stat.label}</span>
                        </div>
                        <p className={`text-2xl font-black ${stat.customColor || 'text-ch-white'} tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors`}>{stat.value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Sub-Header & Global Filter */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white/[0.02] border border-white/5 p-4 rounded-[1.5rem] backdrop-blur-sm">
                <div className="relative flex-1 max-w-lg">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                    <Input
                        placeholder="LOCALIZAR ATIVO AUDITADO..."
                        value={search}
                        onChange={(e) => {
                            setSearch(e.target.value);
                            setPage(0);
                        }}
                        className="pl-12 bg-transparent border-none text-[10px] font-black uppercase tracking-widest focus-visible:ring-0 placeholder:opacity-30"
                    />
                </div>

                <div className="flex items-center gap-4">
                    <span className="text-[9px] font-black text-ch-text-muted uppercase tracking-wide hidden md:block">Filtrar por Status:</span>
                    <Select
                        value={statusFilter}
                        onValueChange={(v) => {
                            setStatusFilter(v);
                            setPage(0);
                        }}
                    >
                        <SelectTrigger className="w-44 bg-ch-dark-gray/40 border-white/5 h-10 rounded-xl text-[9px] font-black uppercase tracking-widest">
                            <SelectValue placeholder="Estado" />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10">
                            <SelectItem value="all" className="text-[10px] font-bold uppercase tracking-widest">Todos os Logs</SelectItem>
                            <SelectItem value="approved" className="text-[10px] font-bold uppercase tracking-widest text-emerald-500">Conformes</SelectItem>
                            <SelectItem value="pending" className="text-[10px] font-bold uppercase tracking-widest text-amber-500">Pendentes</SelectItem>
                            <SelectItem value="rejected" className="text-[10px] font-bold uppercase tracking-widest text-rose-500">Riscos</SelectItem>
                        </SelectContent>
                    </Select>
                    <Button variant="outline" size="icon" className="h-10 w-10 bg-ch-dark-gray/40 border-white/5 rounded-xl hover:text-ch-orange transition-all">
                        <RefreshCw className="w-4 h-4" />
                    </Button>
                </div>
            </motion.div>

            {/* Audits Feed */}
            <motion.div variants={item} className="space-y-4">
                {isLoading ? (
                    <div className="p-20 flex flex-col items-center justify-center gap-4">
                        <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                        <span className="text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed">Sincronizando feed de auditorias...</span>
                    </div>
                ) : paginatedAudits.length > 0 ? (
                    <>
                        <div className="glass rounded-[2rem] overflow-hidden border-white/5 shadow-2xl transition-all">
                            <div className="divide-y divide-white/5">
                                {paginatedAudits.map((audit) => (
                                    <div
                                        key={audit.id}
                                        className="p-6 flex flex-col lg:flex-row lg:items-center gap-6 hover:bg-white/[0.02] cursor-pointer transition-all group"
                                        onClick={() => setSelectedAudit(audit)}
                                    >
                                        <div className="flex items-center gap-5 flex-1 min-w-0">
                                            <div className="w-16 h-16 rounded-[1.25rem] bg-ch-black border border-white/10 overflow-hidden flex-shrink-0 group-hover:border-ch-orange/30 transition-all shadow-lg">
                                                {audit.creatives?.image_url ? (
                                                    <img
                                                        src={audit.creatives.image_url}
                                                        alt={audit.creatives.name}
                                                        className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                                                    />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center text-ch-text-dimmed bg-white/[0.02]">
                                                        <FileSearch className="w-6 h-6 opacity-20" />
                                                    </div>
                                                )}
                                            </div>
                                            <div className="min-w-0">
                                                <p className="font-black text-ch-white truncate uppercase tracking-tight group-hover:text-ch-orange transition-colors">
                                                    {audit.creatives?.name || 'Ativo Externo'}
                                                </p>
                                                <div className="flex items-center gap-3 mt-1.5 font-bold uppercase text-[10px] tracking-widest text-ch-text-dimmed">
                                                    <span className="flex items-center gap-1.5"><ShieldCheck className="w-3 h-3" /> {audit.policies?.name || 'Protocolo Padrão'}</span>
                                                    <span className="opacity-20">|</span>
                                                    <span>{format(new Date(audit.created_at), "dd/MM HH:mm", { locale: ptBR })}</span>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex items-center justify-between lg:justify-end gap-8">
                                            <div className="flex items-center gap-8 border-r border-white/5 pr-8">
                                                <div className="text-right">
                                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mb-1.5">Conformidade</p>
                                                    <p className="text-base font-black text-ch-white tabular-nums">{audit.compliance_score}%</p>
                                                </div>
                                                <div className="text-right">
                                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mb-1.5">Eficiência</p>
                                                    <p className={`text-sm font-black tabular-nums ${getScoreColor(audit.performance_score)}`}>
                                                        {audit.performance_score?.toFixed(0) || '-'}%
                                                    </p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-6 min-w-[150px] justify-end">
                                                {audit.ai_analysis && (
                                                    <div className="p-2 bg-purple-500/10 rounded-lg group-hover:animate-pulse">
                                                        <Sparkles className="w-4 h-4 text-purple-400" />
                                                    </div>
                                                )}
                                                {getStatusBadge(audit.status)}
                                                <ChevronRight className="w-5 h-5 text-ch-text-dimmed group-hover:text-ch-orange group-hover:translate-x-1 transition-all" />
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Pagination Nodes */}
                        {totalPages > 1 && (
                            <div className="flex items-center justify-between bg-white/[0.01] p-6 rounded-3xl border border-white/5">
                                <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">
                                    LOGS {page * PAGE_SIZE + 1} - {Math.min((page + 1) * PAGE_SIZE, filteredAudits.length)} / {filteredAudits.length}
                                </p>
                                <div className="flex items-center gap-4">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPage(p => Math.max(0, p - 1))}
                                        disabled={page === 0}
                                        className="h-10 bg-ch-dark-gray/40 border-white/5 rounded-xl px-4 text-[10px] font-black uppercase tracking-widest hover:text-ch-orange transition-all"
                                    >
                                        <ChevronLeft className="w-4 h-4 mr-2" /> Anterior
                                    </Button>
                                    <div className="flex gap-1">
                                        {Array.from({ length: Math.min(5, totalPages) }).map((_, i) => (
                                            <div key={i} className={`h-1.5 w-4 rounded-full transition-all ${page === i ? 'bg-ch-orange w-8' : 'bg-white/10'}`} />
                                        ))}
                                    </div>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                                        disabled={page >= totalPages - 1}
                                        className="h-10 bg-ch-dark-gray/40 border-white/5 rounded-xl px-4 text-[10px] font-black uppercase tracking-widest hover:text-ch-orange transition-all"
                                    >
                                        Próximo <ChevronRight className="w-4 h-4 ml-2" />
                                    </Button>
                                </div>
                            </div>
                        )}
                    </>
                ) : (
                    <div className="glass rounded-[3rem] p-20 text-center border-white/5 shadow-2xl">
                        <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8">
                            <FileSearch className="w-10 h-10 text-ch-orange animate-pulse" />
                        </div>
                        <h3 className="text-xl font-black text-ch-white uppercase tracking-tight mb-3">Vácuo de Auditorias</h3>
                        <p className="text-ch-text-muted font-medium max-w-sm mx-auto mb-8">Nenhum criativo foi analisado ainda. Inicie o scanner para processar seus ativos.</p>
                        <Button onClick={handleRunBatchAudit} className="bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-[1.5rem] shadow-xl shadow-ch-orange/20 transition-all">
                            Lançar Primeira Varredura
                        </Button>
                    </div>
                )}
            </motion.div>

            {/* Audit Detail Deep Dive */}
            <AnimatePresence>
                {selectedAudit && (
                    <Dialog open={!!selectedAudit} onOpenChange={() => setSelectedAudit(null)}>
                        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto bg-ch-black-soft border-white/10 p-0 rounded-[2.5rem] shadow-[0_0_100px_rgba(242,106,33,0.1)]">
                            <div className="p-8 border-b border-white/5 bg-white/[0.01] flex items-center justify-between sticky top-0 backdrop-blur-3xl z-10">
                                <div className="flex items-center gap-4">
                                    <div className="p-2.5 bg-ch-orange/10 rounded-xl">
                                        <TrendingUp className="w-5 h-5 text-ch-orange" />
                                    </div>
                                    <div>
                                        <h2 className="text-xl font-black text-ch-white uppercase tracking-tight">Relatório de Diagnóstico</h2>
                                        <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-wide mt-1">NÚCLEO DE INTELIGÊNCIA CLICK.HERO</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-4">
                                    {getStatusBadge(selectedAudit.status)}
                                    <Button variant="ghost" className="text-ch-text-muted hover:text-ch-white" onClick={() => setSelectedAudit(null)}>Fechar</Button>
                                </div>
                            </div>

                            <div className="p-10 space-y-10">
                                {/* Visual Context */}
                                <div className="flex flex-col md:flex-row gap-8 items-start">
                                    <div className="w-full md:w-48 aspect-square rounded-[2rem] bg-ch-black border border-white/10 overflow-hidden shadow-2xl shadow-black flex-shrink-0">
                                        {selectedAudit.creatives?.image_url ? (
                                            <img src={selectedAudit.creatives.image_url} alt="" className="w-full h-full object-cover" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center bg-white/[0.02]">
                                                <FileSearch className="w-10 h-10 opacity-10" />
                                            </div>
                                        )}
                                    </div>
                                    <div className="flex-1 space-y-4">
                                        <h3 className="text-2xl font-black text-ch-white uppercase tracking-tight leading-tight">{selectedAudit.creatives?.name || 'Ativo Externo'}</h3>
                                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 pt-4 border-t border-white/5">
                                            <div className="glass-card p-6 rounded-3xl border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all group">
                                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1.5">Índice Conformidade</p>
                                                <div className="flex items-end justify-between">
                                                    <p className="text-2xl font-black text-ch-white tabular-nums group-hover:text-ch-orange transition-colors">{selectedAudit.compliance_score}%</p>
                                                    <TrendingUp className="w-5 h-5 text-emerald-500 mb-1" />
                                                </div>
                                            </div>
                                            <div className="glass-card p-6 rounded-3xl border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all group">
                                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1.5">Índice Eficiência</p>
                                                <p className={`text-2xl font-black tabular-nums ${getScoreColor(selectedAudit.performance_score)}`}>
                                                    {selectedAudit.performance_score?.toFixed(0) || '-'}%
                                                </p>
                                            </div>
                                            <div className="col-span-2">
                                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1.5">Assinatura Temporal</p>
                                                <p className="text-sm font-black text-ch-white uppercase">
                                                    {format(new Date(selectedAudit.created_at), "dd MMMM yyyy HH:mm", { locale: ptBR })}
                                                </p>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* AI Intelligence Block */}
                                {selectedAudit.ai_analysis && (
                                    <div className="glass-premium rounded-[2.5rem] p-8 border-white/10 shadow-2xl relative overflow-hidden group">
                                        <div className="absolute top-0 right-0 p-12 opacity-[0.03] pointer-events-none group-hover:opacity-[0.08] transition-all duration-700">
                                            <Sparkles className="w-48 h-48" />
                                        </div>
                                        <div className="flex items-center gap-3 mb-8">
                                            <div className="p-2.5 bg-purple-500/10 rounded-xl">
                                                <Sparkles className="w-5 h-5 text-purple-400" />
                                            </div>
                                            <h4 className="text-lg font-black text-ch-white uppercase tracking-tight">Análise Cognitiva IA</h4>
                                        </div>

                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                                            <div className="space-y-6">
                                                <div>
                                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-3">Diagnóstico de Tom & Voz</p>
                                                    <p className="text-sm font-medium text-ch-text-dimmed leading-relaxed bg-white/[0.02] p-4 rounded-2xl border border-white/5">{selectedAudit.ai_analysis.tone_analysis || 'Tonalidade neutra voltada para conversão direta.'}</p>
                                                </div>
                                                <div className="grid grid-cols-2 gap-6">
                                                    <div>
                                                        <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2 text-emerald-500">Pontos de Força</p>
                                                        <div className="space-y-3">
                                                            {(selectedAudit.ai_analysis.strengths || ['Alto Contraste', 'CTA Claro']).map((s, i) => (
                                                                <div key={i} className="flex items-center gap-3 px-4 py-3 bg-emerald-500/5 border border-emerald-500/20 rounded-2xl text-[10px] font-black text-emerald-400 uppercase tracking-widest">
                                                                    <CheckCircle2 className="w-3 h-3" /> {s}
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </div>
                                                    <div>
                                                        <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2 text-rose-500">Gargalos</p>
                                                        <div className="space-y-3">
                                                            {(selectedAudit.ai_analysis.weaknesses || ['Risco de Fadiga', 'Extensão de Texto']).map((w, i) => (
                                                                <div key={i} className="flex items-center gap-3 px-4 py-3 bg-rose-500/5 border border-rose-500/20 rounded-2xl text-[10px] font-black text-rose-400 uppercase tracking-widest">
                                                                    <XCircle className="w-3 h-3" /> {w}
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="space-y-6">
                                                <div className="bg-ch-black border border-white/5 p-6 rounded-[2rem] shadow-inner">
                                                    <div className="flex items-center justify-between mb-4">
                                                        <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">Aderência à Política</span>
                                                        <span className="text-sm font-black text-emerald-500 uppercase">Excelente</span>
                                                    </div>
                                                    <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden mb-6">
                                                        <div className="h-full bg-emerald-500 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.3)] transition-all duration-1000" style={{ width: '92%' }} />
                                                    </div>
                                                    <p className="text-[10px] font-medium text-ch-text-dimmed leading-relaxed">
                                                        O ativo cumpre 92% dos rigorosos requisitos de compliance da Click.Hero IA. Baixo risco de bloqueio em redes sociais.
                                                    </p>
                                                </div>
                                                <Button className="w-full bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-2xl h-14 transition-all shadow-xl group">
                                                    Exportar PDF <Zap className="ml-2 w-4 h-4 group-hover:animate-bounce" />
                                                </Button>
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Problems & Recommendations List */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div className="space-y-6">
                                        <h4 className="text-sm font-black text-ch-white uppercase tracking-[.2rem] flex items-center gap-3">
                                            <div className="w-1.5 h-5 bg-rose-500 rounded-full" /> Pontos de Correção
                                        </h4>
                                        <div className="space-y-3">
                                            {(selectedAudit.issues && selectedAudit.issues.length > 0) ? (
                                                selectedAudit.issues.map((issue: AuditIssue, i: number) => (
                                                    <div key={i} className="flex items-start gap-4 p-5 bg-white/[0.02] border border-white/5 rounded-2xl hover:border-white/10 transition-all group">
                                                        <div className="mt-1">{getIssueSeverityIcon(issue.severity)}</div>
                                                        <div>
                                                            <p className="text-[11px] font-black text-ch-white uppercase mb-1 group-hover:text-ch-orange transition-colors">{issue.message}</p>
                                                            <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">{issue.type}</p>
                                                        </div>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="p-8 text-center bg-emerald-500/5 border border-emerald-500/10 rounded-2xl">
                                                    <CheckCircle className="w-8 h-8 text-emerald-500 mx-auto mb-3 opacity-30" />
                                                    <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Nenhuma Irregularidade Detectada</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <div className="space-y-6">
                                        <h4 className="text-sm font-black text-ch-white uppercase tracking-[.2rem] flex items-center gap-3">
                                            <div className="w-1.5 h-5 bg-ch-orange rounded-full" /> Recomendações de Performance
                                        </h4>
                                        <div className="space-y-3">
                                            {(selectedAudit.recommendations && selectedAudit.recommendations.length > 0) ? (
                                                selectedAudit.recommendations.map((rec, i) => (
                                                    <div key={i} className="flex items-start gap-4 p-5 bg-white/[0.02] border border-white/5 rounded-2xl hover:border-white/10 transition-all group">
                                                        <div className="w-6 h-6 bg-ch-orange/10 rounded-lg flex items-center justify-center flex-shrink-0 mt-1">
                                                            <Zap className="w-3.5 h-3.5 text-ch-orange" />
                                                        </div>
                                                        <p className="text-[11px] font-black text-ch-text-muted uppercase group-hover:text-ch-white transition-colors">{rec}</p>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="p-8 text-center bg-white/[0.02] border border-white/5 rounded-2xl opacity-40">
                                                    <Activity className="w-8 h-8 text-ch-text-muted mx-auto mb-3" />
                                                    <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">Aguardando Dados de Tração</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                {/* Detail Bottom Actions */}
                                <div className="flex flex-col md:flex-row gap-4 pt-6 border-t border-white/5">
                                    <Button
                                        onClick={() => navigate(`/criativos/${selectedAudit.creative_id}`)}
                                        className="flex-1 bg-ch-dark-gray/40 hover:bg-white/5 text-ch-white border-white/5 h-16 rounded-2xl font-black uppercase text-[11px] tracking-widest transition-all"
                                    >
                                        <Eye className="w-5 h-5 mr-3 text-ch-orange" />
                                        Inspecionar Ativo Visual
                                    </Button>
                                    <Button
                                        variant="outline"
                                        className="flex-1 bg-transparent border-white/5 hover:bg-white/5 hover:text-ch-orange h-16 rounded-2xl font-black uppercase text-[11px] tracking-widest transition-all"
                                    >
                                        <Briefcase className="w-5 h-5 mr-3" />
                                        Atribuir Tarefa de Ajuste
                                    </Button>
                                </div>
                            </div>
                        </DialogContent>
                    </Dialog>
                )}
            </AnimatePresence>
        </motion.div>
    );
}
